# INSIGHT: encode length before content — '#' can appear inside strings safely
def encode(strs):
    return ''.join(f'{len(s)}#{s}' for s in strs)

def decode(s):
    result, i = [], 0
    while i < len(s):
        j = s.index('#', i)          # find next '#'
        length = int(s[i:j])         # read length
        result.append(s[j+1:j+1+length])  # extract exactly 'length' chars
        i = j + 1 + length           # advance past this string
    return result
# Time: O(n)  Space: O(n)
